ALLOWED_NODE_TYPES = {
    ast.Module, ast.Expr, ast.Constant, ast.Name, ast.BinOp,
    ast.UnaryOp, ast.Compare, ast.BoolOp, ast.Call, ast.List,
    ast.Tuple, ast.Dict, ast.Set, ast.Subscript, ast.Attribute,
