    ast.Del, ast.ListComp, ast.SetComp, ast.DictComp, ast.GeneratorExp,
    ast.comprehension, ast.IfExp, ast.Lambda, ast.Slice, ast.Index,
}


def safe_eval(node, context):
    """Safely evaluate an AST node without using exec()"""
    if isinstance(node, ast.Constant):
        return node.value
    elif isinstance(node, ast.Name):
        if node.id in context:
            return context[node.id]
        elif node.id in SAFE_BUILTINS:
            return SAFE_BUILTINS[node.id]
        else:
            raise NameError(f"Name '{node.id}' is not defined")
    elif isinstance(node, ast.BinOp):
        left = safe_eval(node.left, context)
        right = safe_eval(node.right, context)
        op = OPERATORS.get(type(node.op))
        if op is None:
            raise ValueError(f"Unsupported operator: {type(node.op)}")
        return op(left, right)
    elif isinstance(node, ast.UnaryOp):
        operand = safe_eval(node.operand, context)
        op = OPERATORS.get(type(node.op))
        if op is None:
            raise ValueError(f"Unsupported operator: {type(node.op)}")
        return op(operand)
    elif isinstance(node, ast.Compare):
        left = safe_eval(node.left, context)
        for op, comparator in zip(node.ops, node.comparators):
            right = safe_eval(comparator, context)
            op_func = OPERATORS.get(type(op))
            if op_func is None:
                raise ValueError(f"Unsupported operator: {type(op)}")
            if not op_func(left, right):
                return False
            left = right
        return True
    elif isinstance(node, ast.BoolOp):
        if isinstance(node.op, ast.And):
            result = True
            for value in node.values:
                result = safe_eval(value, context)
                if not result:
                    return result
            return result
        elif isinstance(node.op, ast.Or):
            result = False
            for value in node.values:
                result = safe_eval(value, context)
                if result:
                    return result
            return result
    elif isinstance(node, ast.Call):
        func = safe_eval(node.func, context)
        args = [safe_eval(arg, context) for arg in node.args]
        kwargs = {kw.arg: safe_eval(kw.value, context) for kw in node.keywords}
        return func(*args, **kwargs)
    elif isinstance(node, ast.List):
        return [safe_eval(elt, context) for elt in node.elts]
    elif isinstance(node, ast.Tuple):
        return tuple(safe_eval(elt, context) for elt in node.elts)
    elif isinstance(node, ast.Dict):
        return {safe_eval(k, context): safe_eval(v, context) for k, v in zip(node.keys, node.values)}
    elif isinstance(node, ast.Set):
        return {safe_eval(elt, context) for elt in node.elts}
    elif isinstance(node, ast.Subscript):
        value = safe_eval(node.value, context)
        index = safe_eval(node.slice, context)
        return value[index]
    elif isinstance(node, ast.Slice):
        lower = safe_eval(node.lower, context) if node.lower else None
        upper = safe_eval(node.upper, context) if node.upper else None
        step = safe_eval(node.step, context) if node.step else None
        return slice(lower, upper, step)
    elif isinstance(node, ast.IfExp):
        test = safe_eval(node.test, context)
        return safe_eval(node.body, context) if test else safe_eval(node.orelse, context)
    elif isinstance(node, ast.Attribute):
        value = safe_eval(node.value, context)
        return getattr(value, node.attr)
    elif isinstance(node, ast.Expr):
        return safe_eval(node.value, context)
    else:
        raise ValueError(f"Unsupported node type: {type(node)}")


