    if not module_name.isidentifier() and not all(part.isidentifier() for part in module_name.split('.')):
        return jsonify({"error": "Invalid module name"}), 400

    # Whitelist check - only allow explicitly approved modules
    if module_name not in ALLOWED_MODULES:
        return jsonify({"error": "Module not allowed"}), 403

    try:
        # Use importlib with whitelist validation
        module = importlib.import_module(module_name)

        version = getattr(module, '__version__', 'Version not available')

        # Use JSON response to prevent XSS and template injection
        return jsonify({"module": module_name, "version": version})
    except Exception as e:
        return jsonify({"error": str(e)}), 500

