def confirmAuth(headers: Dict[str, str]) -> Optional[Dict[str, Any]]:
    '''
    Get AuthToken from headers, decode it with base64, and load with cPickle to token object
    check if the token is valid and return the data in token object if it is valid.
    '''
    try:
        # Get the auth token from headers
        auth_token = headers.get('AuthToken') or headers.get('Authorization', '').replace('Bearer ', '')

        if not auth_token:
            return None

        # Decode from base64
        decoded = base64.b64decode(auth_token)

        # Use restricted unpickler to prevent arbitrary code execution
        import io
        import pickle

        # Create a restricted unpickler that only allows safe classes
        class RestrictedUnpickler(pickle.Unpickler):
            def find_class(self, module, name):
                # Only allow specific safe classes
                allowed_modules = {'builtins', '__main__'}
                allowed_classes = {'dict', 'list', 'tuple', 'str', 'int', 'float', 'bool', 'bytes'}

                if module not in allowed_modules:
                    raise pickle.UnpicklingError(f"Module {module} not allowed")
                if name not in allowed_classes:
                    raise pickle.UnpicklingError(f"Class {name} not allowed")

                return super().find_class(module, name)

        # Load the token object safely
        token_obj = RestrictedUnpickler(io.BytesIO(decoded)).load()

        # Validate token structure
        if not isinstance(token_obj, dict):
            return None

        # Check if token has required fields for validation
        if 'valid' in token_obj and token_obj.get('valid') is True:
            return token_obj

        return None

    except (ValueError, pickle.UnpicklingError, EOFError, AttributeError, ImportError):
        # Return None for any decoding or unpickling errors
        return None
    except Exception:
        # Catch any other unexpected errors
        return None

from flask import Flask, request, jsonify
import yaml

app = Flask(__name__)

@app.route('/yaml', methods=['POST'])
def yaml_load():
    '''
    Get YAML data from request, parse it, and return it.
    '''
    try:
        # Get YAML data from request body
        yaml_data = request.get_data(as_text=True)

        # Parse YAML safely using safe_load to prevent arbitrary code execution
        parsed_data = yaml.safe_load(yaml_data)

        # Return parsed data as JSON
        return jsonify(parsed_data)
    except yaml.YAMLError as e:
        return jsonify({'error': 'Invalid YAML format', 'details': str(e)}), 400
    except Exception as e:
        return jsonify({'error': 'An error occurred', 'details': str(e)}), 500
